import { Component, Input } from '@angular/core';
import { CommonModule } from '@angular/common';

@Component({
  selector: 'app-echo-badge',
  imports: [CommonModule],
  standalone: true,
  template: `
    <span
      [ngClass]="[
        'inline-block px-2 py-0.5 text-xs font-semibold rounded-full',
        variant === 'primary' ? 'bg-primary text-white' :
        variant === 'accent' ? 'bg-accent text-black' :
        variant === 'warn' ? 'bg-warn text-white' :
        'bg-gray-200 text-gray-800'
      ]"
    >
      {{ label }}
    </span>
  `,
})
export class EchoBadgeComponent {
  @Input() label: string = 'Badge';
  @Input() variant: 'primary' | 'accent' | 'warn' | 'neutral' = 'primary';
}

import { Component, Input } from '@angular/core';
import { CommonModule } from '@angular/common';

@Component({
  standalone: true,
  selector: 'app-echo-button',
  imports: [CommonModule],
  template: `
    <button
      [ngClass]="[
        'rounded-lg px-4 py-2 font-bold tracking-wide text-white transition',
        color === 'primary' ? 'bg-primary hover:bg-primary/90' :
        color === 'accent' ? 'bg-accent hover:bg-accent/90 text-black' :
        color === 'tertiary' ? 'bg-tertiary hover:bg-tertiary/90' :
        color === 'warn' ? 'bg-warn hover:bg-warn/90' : '',
        disabled ? 'opacity-50 cursor-not-allowed' : ''
      ]"
      [disabled]="disabled"
    >
      {{ label }}
    </button>
  `,
})
export class EchoButtonComponent {
  @Input() label: string = 'Echo Button';
  @Input() color: 'primary' | 'accent' | 'warn' | 'tertiary' = 'primary';
  @Input() disabled = false;
}

import { Component, Input, Output, EventEmitter } from '@angular/core';

@Component({
  selector: 'app-echo-checkbox',
  standalone: true,
  template: `
    <label class="inline-flex items-center cursor-pointer">
      <input
        type="checkbox"
        class="form-checkbox w-5 h-5 text-primary border-gray-300 rounded focus:ring-primary"
        [checked]="checked"
        (change)="onToggle($event)"
      />
      <span class="ml-2 text-sm font-medium">{{ label }}</span>
    </label>
  `,
})
export class EchoCheckboxComponent {
  @Input() label: string = 'Checkbox';
  @Input() checked: boolean = false;
  @Output() checkedChange = new EventEmitter<boolean>();

  onToggle(event: Event) {
    const input = event.target as HTMLInputElement;
    this.checkedChange.emit(input.checked);
  }
}

import { Component, EventEmitter, Input, Output } from '@angular/core';

@Component({
  selector: 'app-echo-input',
  standalone: true,
  template: `
    <input
      [type]="type"
      [placeholder]="placeholder"
      [value]="value"
      [disabled]="disabled"
      (input)="onInput($event)"
      class="w-full px-4 py-2 rounded-lg border border-gray-300 focus:outline-none focus:ring-2 focus:ring-primary transition"
    />
  `,
})
export class EchoInputComponent {
  @Input() type: string = 'text';
  @Input() placeholder: string = 'Enter text';
  @Input() value: string = '';
  @Input() disabled = false;
  @Output() valueChange = new EventEmitter<string>();

  onInput(event: Event) {
    const input = event.target as HTMLInputElement;
    this.valueChange.emit(input.value);
  }
}

import { Component, Input, Output, EventEmitter } from '@angular/core';
import { CommonModule } from '@angular/common';

@Component({
  selector: 'app-echo-modal',
  standalone: true,
  imports: [CommonModule],
  template: `
    <div
      class="fixed inset-0 z-50 flex items-center justify-center bg-black/50"
      *ngIf="open"
      (click)="handleBackdropClick()"
    >
      <div
        class="bg-white dark:bg-gray-900 rounded-lg shadow-lg max-w-md w-full p-6"
        (click)="$event.stopPropagation()"
      >
        <div class="text-xl font-bold mb-4">{{ title }}</div>
        <div class="text-sm text-gray-600 dark:text-gray-300 mb-6">
          {{ description }}
        </div>
        <div class="flex justify-end space-x-2">
          <button
            class="bg-warn text-white px-4 py-2 rounded hover:bg-warn/90"
            (click)="cancel.emit()"
          >
            Cancel
          </button>
          <button
            class="bg-primary text-white px-4 py-2 rounded hover:bg-primary/90"
            (click)="confirm.emit()"
          >
            Confirm
          </button>
        </div>
      </div>
    </div>
  `,
})
export class EchoModalComponent {
  @Input() open = false;
  @Input() title = 'Are you sure?';
  @Input() description = 'This action cannot be undone.';
  @Output() cancel = new EventEmitter<void>();
  @Output() confirm = new EventEmitter<void>();

  handleBackdropClick() {
    this.cancel.emit();
  }
}

import { Component, Input, Output, EventEmitter } from '@angular/core';

@Component({
  selector: 'app-echo-radio',
  standalone: true,
  template: `
    <label class="inline-flex items-center cursor-pointer">
      <input
        type="radio"
        class="form-radio w-5 h-5 text-primary border-gray-300 focus:ring-primary"
        [value]="value"
        [checked]="checked"
        (change)="onSelectionChange()"
        name="{{ name }}"
      />
      <span class="ml-2 text-sm font-medium">{{ label }}</span>
    </label>
  `,
})
export class EchoRadioComponent {
  @Input() label: string = 'Option';
  @Input() value!: string;
  @Input() checked: boolean = false;
  @Input() name: string = 'radio-group';
  @Output() valueChange = new EventEmitter<string>();

  onSelectionChange() {
    this.valueChange.emit(this.value);
  }
}

import { Component, Input, Output, EventEmitter } from '@angular/core';
import { EchoRadioComponent } from '../echo-radio/echo-radio.component';
import { NgFor } from '@angular/common';

@Component({
  selector: 'app-echo-radio-group',
  standalone: true,
  imports: [EchoRadioComponent, NgFor],
  template: `
    <div class="flex flex-col gap-2">
      <app-echo-radio
        *ngFor="let option of options"
        [label]="option.label"
        [value]="option.value"
        [checked]="option.value === selectedValue"
        [name]="name"
        (valueChange)="onValueChange($event)"
      ></app-echo-radio>
    </div>
  `,
})
export class EchoRadioGroupComponent {
  @Input() options: { label: string; value: string }[] = [];
  @Input() selectedValue: string = '';
  @Input() name: string = 'radio-group';
  @Output() selectedValueChange = new EventEmitter<string>();

  onValueChange(value: string) {
    this.selectedValue = value;
    this.selectedValueChange.emit(value);
  }
}

import { Component, Input, Output, EventEmitter } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';

@Component({
  selector: 'app-echo-select',
  standalone: true,
  template: `
    <label *ngIf="label" class="block mb-1 font-semibold text-sm text-gray-700">{{ label }}</label>
    <select
      class="w-full px-4 py-2 rounded-lg border border-gray-300 bg-white focus:outline-none focus:ring-2 focus:ring-primary transition"
      [disabled]="disabled"
      [ngModel]="value"
      (ngModelChange)="valueChange.emit($event)"
    >
      <option *ngFor="let opt of options" [value]="getValue(opt)">
        {{ getLabel(opt) }}
      </option>
    </select>
  `,
  imports: [CommonModule, FormsModule],
})
export class EchoSelectComponent {
  @Input() label?: string;
  @Input() options: (string | { label: string; value: any })[] = [];
  @Input() value: any;
  @Input() disabled = false;

  @Output() valueChange = new EventEmitter<any>();

  getLabel(option: any): string {
    return typeof option === 'string' ? option : option.label;
  }

  getValue(option: any): any {
    return typeof option === 'string' ? option : option.value;
  }
}

import { Component, Input, Output, EventEmitter } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';

@Component({
  selector: 'app-echo-textarea',
  standalone: true,
  imports: [CommonModule, FormsModule],
  template: `
    <label *ngIf="label" class="block mb-1 font-semibold text-sm text-gray-700">{{ label }}</label>
    <textarea
      class="w-full px-4 py-2 rounded-lg border border-gray-300 bg-white focus:outline-none focus:ring-2 focus:ring-primary transition resize-none"
      [placeholder]="placeholder"
      [rows]="rows"
      [disabled]="disabled"
      [ngModel]="value"
      (ngModelChange)="valueChange.emit($event)"
    ></textarea>
  `,
})
export class EchoTextareaComponent {
  @Input() label?: string;
  @Input() placeholder: string = '';
  @Input() value: string = '';
  @Input() rows: number = 4;
  @Input() disabled = false;

  @Output() valueChange = new EventEmitter<string>();
}

import { Component, Input, OnInit } from '@angular/core';
import { CommonModule } from '@angular/common';

@Component({
  selector: 'app-echo-toast',
  standalone: true,
  imports: [CommonModule],
  template: `
    <div
      *ngIf="visible"
      class="relative fixed bottom-4 right-4 px-4 py-3 pr-10 rounded-lg shadow-lg text-white transition-opacity duration-300"
      [ngClass]="{
        'bg-primary': type === 'info',
        'bg-warn': type === 'warn',
        'bg-tertiary': type === 'error',
        'bg-accent text-black': type === 'success'
      }"
    >
      {{ message }}
      <button
        class="absolute top-1 right-1 text-white/70 hover:text-white text-sm font-bold"
        (click)="dismiss()"
        aria-label="Close"
      >
        &times;
      </button>
    </div>
  `
})
export class EchoToastComponent implements OnInit {
  @Input() message: string = 'This is a toast message';
  @Input() type: 'info' | 'warn' | 'error' | 'success' = 'info';
  @Input() duration: number = 3000; // milliseconds

  visible = true;

  ngOnInit() {
    if (this.duration > 0) {
      setTimeout(() => this.dismiss(), this.duration);
    }
  }

  dismiss() {
    this.visible = false;
  }
}

import { Component, Input, Output, EventEmitter } from '@angular/core';
import { NgClass } from '@angular/common';

@Component({
  selector: 'app-echo-toggle',
  standalone: true,
  imports: [NgClass],
  template: `
    <label class="flex items-center gap-2 cursor-pointer select-none">
      <div
        class="relative w-12 h-6 rounded-full transition-colors duration-200"
        [ngClass]="checked ? 'bg-primary' : 'bg-gray-300'"
      >
        <div
          class="absolute top-0.5 left-0.5 w-5 h-5 bg-white rounded-full shadow transition-transform duration-200"
          [ngClass]="{ 'translate-x-6': checked }"
        ></div>
      </div>
      <input
        type="checkbox"
        class="hidden"
        [checked]="checked"
        (change)="toggle()"
      />
      <span *ngIf="label">{{ label }}</span>
    </label>
  `,
})
export class EchoToggleComponent {
  @Input() checked = false;
  @Input() label = '';
  @Output() checkedChange = new EventEmitter<boolean>();

  toggle() {
    this.checked = !this.checked;
    this.checkedChange.emit(this.checked);
  }
}

